#!/usr/bin/env pwsh
$basedir=Split-Path $MyInvocation.MyCommand.Definition -Parent

$exe=""
$pathsep=":"
$env_node_path=$env:NODE_PATH
$new_node_path="E:\vscode_workspace\基于 SpringBoot+Vue 的海外物品代购系统的设计与实现\client\node_modules\.pnpm\rollup@4.60.1\node_modules\rollup\node_modules;E:\vscode_workspace\基于 SpringBoot+Vue 的海外物品代购系统的设计与实现\client\node_modules\.pnpm\rollup@4.60.1\node_modules;E:\vscode_workspace\基于 SpringBoot+Vue 的海外物品代购系统的设计与实现\client\node_modules\.pnpm\node_modules"
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  # Fix case when both the Windows and Linux builds of Node
  # are installed in the same directory
  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/mnt/e/vscode_workspace/基于 SpringBoot+Vue 的海外物品代购系统的设计与实现/client/node_modules/.pnpm/rollup@4.60.1/node_modules/rollup/node_modules:/mnt/e/vscode_workspace/基于 SpringBoot+Vue 的海外物品代购系统的设计与实现/client/node_modules/.pnpm/rollup@4.60.1/node_modules:/mnt/e/vscode_workspace/基于 SpringBoot+Vue 的海外物品代购系统的设计与实现/client/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
  $env:NODE_PATH=$new_node_path
} else {
  $env:NODE_PATH="$new_node_path$pathsep$env_node_path"
}

$ret=0
if (Test-Path "$basedir/node$exe") {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/node$exe"  "$basedir/../rollup/dist/bin/rollup" $args
  } else {
    & "$basedir/node$exe"  "$basedir/../rollup/dist/bin/rollup" $args
  }
  $ret=$LASTEXITCODE
} else {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "node$exe"  "$basedir/../rollup/dist/bin/rollup" $args
  } else {
    & "node$exe"  "$basedir/../rollup/dist/bin/rollup" $args
  }
  $ret=$LASTEXITCODE
}
$env:NODE_PATH=$env_node_path
exit $ret
